type Result<T, E = Error> = { ok: true; value: T } | { ok: false; error: E };

async function transferFunds(from: string, to: string, amount: number): Promise<Result<Transaction, TransferError>> {
  if (amount <= 0) return { ok: false, error: { type: 'invalid_amount' } };
  const r = await fetch('/api/transfer', { method: 'POST', body: JSON.stringify({ from, to, amount }) });
  if (!r.ok) {
    const data = await r.json();
    return { ok: false, error: { type: 'api_error', code: data.code } };
  }
  return { ok: true, value: await r.json() };
}

