class CircuitBreaker {
  private failures = 0;
  private openUntil = 0;
  constructor(private threshold = 5, private resetMs = 60000) {}
  async call<T>(fn: () => Promise<T>): Promise<T> {
    if (Date.now() < this.openUntil) throw new Error('Circuit open');
    try {
      const result = await fn();
      this.failures = 0;
      return result;
    } catch (e) {
      this.failures++;
      if (this.failures >= this.threshold) {
        this.openUntil = Date.now() + this.resetMs;
      }
      throw e;
    }
  }
}

const breaker = new CircuitBreaker();
export async function callFlaky() {
  return breaker.call(() => fetch('/api/flaky').then(r => r.json()));
}

export async function importWithRetry<T>(loader: () => Promise<T>): Promise<T> {
  try {
    return await loader();
  } catch (error: any) {
    if (error.name === 'ChunkLoadError' || /Loading chunk/.test(error.message)) {
      // Force reload (simple)
      window.location.reload();
      throw error;
    }
    throw error;
  }
}

