async function updateItem(id: string, changes: Partial<Item>, version: number) {
  const r = await fetch(`/api/items/${id}`, {
    method: 'PATCH',
    body: JSON.stringify({ ...changes, expectedVersion: version })
  });
  if (r.status === 409) {
    const latest = await r.json();
    // Conflict - show user, offer merge
    throw new ConflictError(latest);
  }
  return r.json();
}

