type ModalState =
  | { status: 'idle' }
  | { status: 'loading' }
  | { status: 'error'; message: string }
  | { status: 'success'; data: Result };

function Modal() {
  const [state, setState] = useState<ModalState>({ status: 'idle' });
  if (state.status === 'loading') return <Spinner />;
  if (state.status === 'error') return <Error message={state.message} />;
  if (state.status === 'success') return <Success data={state.data} />;
  return <Idle onStart={() => setState({ status: 'loading' })} />;
}

